/**
 * Dataset registry — one entry per KIND from src/data/taxonomy.json
 * (Dominik 2026-07-11: the toggles ARE the things — Forts, Villas,
 * Temples, Mines — under the overall panel groups; no invented
 * intermediate categories). GENERATED by scripts/gen-atlas-modules.py
 * from taxonomy.json + atlas chunk counts — regenerate, don't hand-edit.
 * Colors mark the kind's family (military red, religious gold, ...).
 * group '_hidden' = drawn by another toggle (settlement rides with the
 * Settlements toggle), not listed in the panel.
 */

export interface DatasetConfig {
  id: string
  label: string
  group: string
  /** atlas kind chunk under src/data/entities/atlas/ */
  file: string

  color: string
  fillColor: string

  minZoom: number
  maxSample?: number

  temporalFilter: boolean

  activeClass: string
  attribution?: string
}

